  "modes.ko-system.construction": "Page Under Construction <span>This page is being updated. Content may be incomplete.</span>",
  "modes.ko-system.intro": "The KO System is a classic single-elimination knockout bracket. Teams are drawn into a bracket before the tournament starts, and each match is decisive — the winner advances, the loser is eliminated. The bracket progresses round by round until one team remains. TournaQ handles the full bracket setup, match progression, and result recording automatically.",
  "modes.ko-system.detail.teams.label": "Teams",
  "modes.ko-system.detail.teams.value": "4, 8, 16, 32",
  "modes.ko-system.detail.elimination.label": "Elimination",
  "modes.ko-system.detail.elimination.value": "Single loss",
  "modes.ko-system.detail.bracket.label": "Bracket",
  "modes.ko-system.detail.bracket.value": "Fixed draw",
  "modes.ko-system.detail.tournament.label": "Tournament required",
  "modes.ko-system.detail.tournament.value": "Yes",
  "modes.ko-system.how.title": "How it works",
  "modes.ko-system.how.text": "The organiser sets up the bracket before play begins — choosing the number of teams, seeding method (random draw or manual seeding), and whether a third-place match is played. TournaQ generates the full bracket and assigns first-round match-ups. As results are entered, the bracket updates automatically and the next round is populated. The final match produces an outright winner.",
  "modes.ko-system.setup.title": "Setup options",
  "modes.ko-system.setup.li1": "Number of teams: 4, 8, 16, or 32 (power-of-two draws)",
  "modes.ko-system.setup.li2": "Seeding: random draw or manual placement",
  "modes.ko-system.setup.li3": "Third-place play-off: optional bronze medal match",
  "modes.ko-system.setup.li4": "Match format: configurable sets and points per match",
  "modes.ko-system.setup.li5": "Byes: automatically assigned for non-power-of-two team counts",
