  "modes.doghouse.detail.teams.value": "3+",
  "modes.doghouse.detail.courts.label": "Courts",
  "modes.doghouse.detail.courts.value": "1 per group",
  "modes.doghouse.detail.length.label": "Match length",
  "modes.doghouse.detail.length.value": "Short sets",
  "modes.doghouse.detail.tournament.label": "Tournament required",
  "modes.doghouse.detail.tournament.value": "Yes",
  "modes.doghouse.how.title": "How it works",
  "modes.doghouse.how.text": "The organiser registers all teams and sets the match format (typically a single short set to keep the queue moving). TournaQ tracks the queue order, records each result, and updates standings in real time. The team with the most wins when the session ends is the winner. Matches are intentionally short — the energy comes from the constant rotation and the pressure of defending on court.",
